package cmd

import (
	"encoding/json"
	"fmt"
	"os"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/sequence"
)

var sequenceFormat string
var sequenceStatus string
var sequenceLimit int
var sequencePauseCmd = &cobra.Command{
	Use:   "pause <enrollment-id>",
	Short: "Pause an active sequence enrollment",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := sequence.PauseEnrollment(d, args[0]); err != nil {
			return err
		}
		fmt.Printf("  ✓ Paused %s\n", args[0])
		return nil
	},
}

var sequenceResumeCmd = &cobra.Command{
	Use:   "resume <enrollment-id>",
	Short: "Resume a paused sequence enrollment",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		if err := sequence.ResumeEnrollment(d, args[0]); err != nil {
			return err
		}
		fmt.Printf("  ✓ Resumed %s\n", args[0])
		return nil
	},
}

var sequenceCmd = &cobra.Command{
	Use:   "sequence",
	Short: "Inspect sequence enrollments and templates",
}

var sequenceListCmd = &cobra.Command{
	Use:   "list",
	Short: "List sequence enrollments",
	RunE: func(cmd *cobra.Command, args []string) error {
		d, err := db.Open()
		if err != nil {
			return err
		}
		defer d.Close()

		enrollments, err := sequence.ListEnrollments(d, sequenceStatus, sequenceLimit)
		if err != nil {
			return err
		}

		if sequenceFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(enrollments)
		}

		if len(enrollments) == 0 {
			fmt.Println("  No sequence enrollments yet.")
			return nil
		}

		for _, enrollment := range enrollments {
			fmt.Printf("  [%s] %s → %s\n", enrollment.Status, enrollment.SequenceName, enrollment.ContactEmail)
			fmt.Printf("    id: %s\n", enrollment.ID)
			fmt.Printf("    mailbox: %s\n", enrollment.MailboxEmail)
			if enrollment.CampaignName != "" {
				fmt.Printf("    campaign: %s\n", enrollment.CampaignName)
			}
			fmt.Printf("    progress: step %d/%d\n", enrollment.CurrentStep, enrollment.TotalSteps)
			if enrollment.ReplyState != "" {
				fmt.Printf("    reply state: %s\n", enrollment.ReplyState)
			}
			if enrollment.StatusReason != "" {
				fmt.Printf("    reason: %s\n", enrollment.StatusReason)
			}
			if enrollment.NextDueAt != "" {
				fmt.Printf("    next due: %s\n", shortDate(enrollment.NextDueAt))
			}
		}
		return nil
	},
}

var sequenceTemplatesCmd = &cobra.Command{
	Use:   "templates",
	Short: "List built-in sequence templates",
	RunE: func(cmd *cobra.Command, args []string) error {
		templates := sequence.BuiltInTemplates()
		if sequenceFormat == "json" {
			enc := json.NewEncoder(os.Stdout)
			enc.SetIndent("", "  ")
			return enc.Encode(templates)
		}

		for _, template := range templates {
			fmt.Printf("  %s\n", template.Name)
			for _, step := range template.Steps {
				fmt.Printf("    step %d: %s (%s, +%s)\n", step.StepNumber, step.Name, step.SendType, step.Delay)
			}
		}
		return nil
	},
}

func init() {
	sequenceCmd.PersistentFlags().StringVar(&sequenceFormat, "format", "", "Output format (json)")
	sequenceListCmd.Flags().StringVar(&sequenceStatus, "status", "", "Filter by status")
	sequenceListCmd.Flags().IntVar(&sequenceLimit, "limit", 0, "Max results")
	sequenceCmd.AddCommand(sequenceListCmd)
	sequenceCmd.AddCommand(sequenceTemplatesCmd)
	sequenceCmd.AddCommand(sequencePauseCmd)
	sequenceCmd.AddCommand(sequenceResumeCmd)
	rootCmd.AddCommand(sequenceCmd)
}

