 57→		}
 58→
 59→		effectiveSendType := sequence.NormalizeSendType(sendSendType)
 60→		var task *sequence.Task
 61→		policyMailboxID := mailbox.ID
 62→		if sendSequence != "" {
 63→			effectiveSendType = sequence.SendTypeFirstTouch
 64→		}
 65→		if sendTaskID != "" {
 66→			task, err = sequence.TaskByID(d, sendTaskID)
 67→			if err != nil {
 68→				return err
 69→			}
 70→			effectiveSendType = task.SendType
 71→			policyMailboxID = task.MailboxID
 72→			if sendTo == "" {
 73→				sendTo = task.ContactEmail
 74→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 75→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 76→			}
 77→		}
 78→
 79→		sentAt := timeNow()
 80→		if sendTo == "" {
 81→			return fmt.Errorf("recipient (--to) is required")
 82→		}
 83→		if sendSequence != "" {
 84→			enrollment, err := sequence.ActiveEnrollmentForContact(d, mailbox.ID, sendTo)
 85→			if err != nil {
 86→				return err
 87→			}
 88→			if enrollment != nil {
 89→				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
 90→			}
 91→		}
 92→		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
 93→			return err
 94→		} else if suppressed {
 95→			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
 96→		}
 97→
 98→		if err := sequence.CanSend(d, policyMailboxID, effectiveSendType, sentAt); err != nil {
 99→			return err
100→		}
101→
102→		srv, err := email.NewClient("")
103→		if err != nil {
104→			return fmt.Errorf("connecting to Gmail: %w", err)
105→		}
106→
107→		sent, err := email.Send(srv, gmail.Account, email.SendOptions{
108→			To:      sendTo,
109→			Cc:      sendCc,
110→			Subject: sendSubject,
111→			Body:    sendBody,
112→		})
113→		if err != nil {
114→			return err
115→		}
116→
117→		if err := sequence.RecordSend(d, policyMailboxID, effectiveSendType, sentAt); err != nil {
118→			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
119→		}
120→		if err := email.StoreEmail(d, &email.RawMessage{
121→			ID:        sent.MessageID,
122→			Source:    "gmail",
123→			Direction: "outbound",
124→			ThreadID:  sent.ThreadID,
125→			Subject:   sendSubject,
126→			FromEmail: gmail.Account,
127→			ToEmails:  recipientsJSON(sendTo),
128→			CcEmails:  recipientsJSON(sendCc),
129→			Date:      sentAt.UTC().Format(time.RFC3339),
130→			Labels:    `["SENT"]`,
131→		}); err != nil {
132→			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
133→		}
134→
135→		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
136→
137→		if sendSequence != "" {
138→			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
139→				SequenceName: sendSequence,
140→				CampaignName: sendCampaign,
141→				MailboxID:    mailbox.ID,
142→				ContactEmail: sendTo,
143→				ContactName:  sendContactName,
144→				Subject:      sendSubject,
145→				ThreadID:     sent.ThreadID,
146→				MessageID:    sent.MessageID,
147→				SentAt:       sentAt,
148→			})
149→			if err != nil {
150→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
151→			}
152→
153→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
154→			if nextTask != nil {
155→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
156→			}
157→		}
158→
159→		if task != nil {
160→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
