 3→import (
 4→	"encoding/base64"
 5→	"fmt"
 6→	"strings"
 7→
 8→	gm "google.golang.org/api/gmail/v1"
 9→)
10→
11→// SendOptions holds the fields for composing an email.
12→type SendOptions struct {
13→	To      string // recipient email
14→	Cc      string // optional CC
15→	Subject string
16→	Body    string // plain text body
17→}
18→
19→type SentMessage struct {
20→	MessageID string
21→	ThreadID  string
22→}
23→
24→// Send sends an email via the Gmail API.
25→func Send(srv *gm.Service, from string, opts SendOptions) (*SentMessage, error) {
26→	if opts.To == "" {
27→		return nil, fmt.Errorf("recipient (--to) is required")
28→	}
29→	if opts.Subject == "" {
30→		return nil, fmt.Errorf("subject (--subject) is required")
31→	}
32→	if opts.Body == "" {
33→		return nil, fmt.Errorf("body (--body) is required")
34→	}
35→
36→	raw := buildRawMessage(from, opts)
37→	msg := &gm.Message{
38→		Raw: base64.URLEncoding.EncodeToString([]byte(raw)),
39→	}
40→
41→	sent, err := srv.Users.Messages.Send("me", msg).Do()
42→	if err != nil {
43→		return nil, fmt.Errorf("sending email: %w", err)
44→	}
45→
46→	return &SentMessage{
47→		MessageID: sent.Id,
48→		ThreadID:  sent.ThreadId,
49→	}, nil
50→}
51→
52→func buildRawMessage(from string, opts SendOptions) string {
53→	var b strings.Builder
54→	b.WriteString("From: " + from + "\r\n")
55→	b.WriteString("To: " + opts.To + "\r\n")
56→	if opts.Cc != "" {
57→		b.WriteString("Cc: " + opts.Cc + "\r\n")
58→	}
59→	b.WriteString("Subject: " + opts.Subject + "\r\n")
60→	b.WriteString("MIME-Version: 1.0\r\n")
61→	b.WriteString("Content-Type: text/plain; charset=\"UTF-8\"\r\n")
62→	b.WriteString("\r\n")
63→	b.WriteString(opts.Body)
64→	return b.String()
65→}
