 40→		Connectors:     make(map[string]ConnectorState),
 41→		SetupCompleted: false,
 42→	}
 43→}
 44→
 45→// Load reads config from disk.
 46→func Load() (*Config, error) {
 47→	data, err := os.ReadFile(configFile)
 48→	if err != nil {
 49→		return nil, fmt.Errorf("reading config: %w", err)
 50→	}
 51→	var cfg Config
 52→	if err := json.Unmarshal(data, &cfg); err != nil {
 53→		return nil, fmt.Errorf("parsing config: %w", err)
 54→	}
 55→	if cfg.Connectors == nil {
 56→		cfg.Connectors = make(map[string]ConnectorState)
 57→	}
 58→	return &cfg, nil
 59→}
