147→func shortDate(value string) string {
148→	if value == "" {
149→		return value
150→	}
151→	if ts, err := time.Parse(time.RFC3339, value); err == nil {
152→		return ts.In(time.Local).Format("2006-01-02 15:04")
153→	}
154→	if len(value) >= 16 {
155→		return value[:16]
156→	}
157→	if len(value) >= 10 {
158→		return value[:10]
159→	}
160→	return value
161→}
162→
163→func joinRecipients(recipients []string) string {
164→	if len(recipients) == 0 {
165→		return "(unknown recipient)"
166→	}
167→	return strings.Join(recipients, ", ")
168→}
169→
170→func relativeDueStatus(value string, now time.Time) string {
171→	dueAt, err := time.Parse(time.RFC3339, value)
172→	if err != nil {
173→		return "due"
174→	}
175→
176→	delta := dueAt.Sub(now.UTC())
177→	if delta >= 0 {
178→		if delta < time.Minute {
179→			return "due soon"
180→		}
181→		if delta < time.Hour {
182→			return fmt.Sprintf("in %dm", int(delta.Round(time.Minute)/time.Minute))
183→		}
184→		if delta < 24*time.Hour {
185→			return fmt.Sprintf("in %dh", int(delta.Round(time.Hour)/time.Hour))
186→		}
187→		return fmt.Sprintf("in %dd", int(delta.Hours()/24))
188→	}
189→
190→	overdue := -delta
191→	if overdue < time.Hour {
192→		return fmt.Sprintf("%dm overdue", int(overdue.Round(time.Minute)/time.Minute))
193→	}
194→	if overdue < 24*time.Hour {
195→		return fmt.Sprintf("%dh overdue", int(overdue.Round(time.Hour)/time.Hour))
196→	}
197→	return fmt.Sprintf("%dd overdue", int(overdue.Hours()/24))
198→}
199→
200→func init() {
201→	tasksCmd.PersistentFlags().StringVar(&tasksFormat, "format", "", "Output format (json)")
202→	tasksListCmd.Flags().IntVar(&tasksAfterDays, "after-days", 3, "Mark follow-ups due this many days after the last outbound email")
203→	tasksListCmd.Flags().BoolVar(&tasksIncludeFuture, "all", false, "Include future follow-ups that are not due yet")
204→	tasksListCmd.Flags().IntVar(&tasksLimit, "limit", 0, "Max results")
205→	tasksSnoozeCmd.Flags().IntVar(&tasksSnoozeDays, "days", 1, "Number of days to push the task forward")
206→	tasksCancelCmd.Flags().StringVar(&tasksCancelReason, "reason", "manual cancel", "Reason recorded for cancellation")
207→	tasksCmd.AddCommand(tasksListCmd)
208→	tasksCmd.AddCommand(tasksSnoozeCmd)
209→	tasksCmd.AddCommand(tasksCancelCmd)
