  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→	"time"
  9→
 10→	gm "google.golang.org/api/gmail/v1"
 11→)
 12→
 13→type RawMessage struct {
 14→	ID          string
 15→	Source      string
 16→	Direction   string
 17→	ThreadID    string
 18→	Subject     string
 19→	FromEmail   string
 20→	ToEmails    string // JSON array
 21→	CcEmails    string // JSON array
 22→	Date        string
 23→	Snippet     string
 24→	BodyPreview string
 25→	Labels      string // JSON array
 26→}
 27→
 28→type SyncResult struct {
 29→	Fetched  int
 30→	Stored   int
 31→	Cursor   string
 32→	Duration time.Duration
 33→}
 34→
 35→func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 36→	start := time.Now()
 37→	result := &SyncResult{}
 38→
 39→	var cursor string
 40→	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 41→
 42→	query := "in:sent"
 43→	if cursor == "" {
 44→		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 45→		query += " after:" + since
 46→	}
 47→
 48→	var pageToken string
 49→	for {
 50→		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 51→		if pageToken != "" {
 52→			req = req.PageToken(pageToken)
 53→		}
 54→
 55→		resp, err := req.Do()
 56→		if err != nil {
 57→			return result, fmt.Errorf("listing messages: %w", err)
 58→		}
 59→
 60→		for _, msg := range resp.Messages {
 61→			result.Fetched++
 62→
 63→			if cursor != "" {
 64→				var exists int
 65→				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 66→				if exists == 1 {
 67→					continue
 68→				}
 69→			}
 70→
 71→			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 72→				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 73→			if err != nil {
 74→				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 75→				continue
 76→			}
 77→
 78→			email := parseMessage(full)
 79→			if err := StoreEmail(d, email); err != nil {
 80→				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 81→				continue
 82→			}
 83→			result.Stored++
 84→		}
 85→
 86→		pageToken = resp.NextPageToken
 87→		if pageToken == "" {
 88→			break
 89→		}
 90→	}
 91→
 92→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 93→	result.Duration = time.Since(start)
 94→
 95→	d.Exec(
 96→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 97→		 VALUES ('gmail', 'email', ?, ?, ?)
 98→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 99→		result.Cursor, result.Cursor, result.Stored,
100→		result.Cursor, result.Cursor, result.Stored,
101→	)
102→
103→	return result, nil
104→}
105→
106→func StoreEmail(d *sql.DB, e *RawMessage) error {
107→	source := e.Source
108→	if source == "" {
109→		source = "gmail"
110→	}
111→	direction := e.Direction
112→	if direction == "" {
113→		direction = "outbound"
114→	}
115→
116→	isNewMessage := true
117→	var existing int
118→	err := d.QueryRow(`SELECT 1 FROM emails WHERE id = ?`, e.ID).Scan(&existing)
119→	if err == nil {
120→		isNewMessage = false
121→	} else if err != nil && err != sql.ErrNoRows {
122→		return err
123→	}
124→
125→	_, err = d.Exec(`
126→		INSERT INTO emails (id, source, direction, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
127→		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
128→		ON CONFLICT(id) DO UPDATE SET
129→			source = excluded.source,
130→			direction = excluded.direction,
131→			subject = excluded.subject,
132→			snippet = excluded.snippet,
133→			body_preview = excluded.body_preview,
134→			labels = excluded.labels,
135→			synced_at = datetime('now')`,
136→		e.ID, source, direction, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
137→		e.Date, e.Snippet, e.BodyPreview, e.Labels,
138→	)
139→	if err != nil {
140→		return err
141→	}
142→	return upsertContactsForMessage(d, source, direction, e, isNewMessage)
143→}
144→
145→func parseMessage(msg *gm.Message) *RawMessage {
146→	e := &RawMessage{
147→		ID:        msg.Id,
148→		Source:    "gmail",
149→		Direction: "outbound",
150→		ThreadID:  msg.ThreadId,
151→		Snippet:   msg.Snippet,
152→		CcEmails:  "[]",
153→		ToEmails:  "[]",
154→		Labels:    "[]",
155→	}
156→
157→	for _, h := range msg.Payload.Headers {
158→		switch h.Name {
159→		case "Subject":
160→			e.Subject = h.Value
161→		case "From":
162→			e.FromEmail = extractEmail(h.Value)
163→		case "To":
164→			e.ToEmails = emailsToJSON(h.Value)
165→		case "Cc":
166→			e.CcEmails = emailsToJSON(h.Value)
167→		case "Date":
168→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
169→				e.Date = t.UTC().Format(time.RFC3339)
170→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
171→				e.Date = t.UTC().Format(time.RFC3339)
172→			} else {
173→				e.Date = h.Value
174→			}
175→		}
176→	}
177→
178→	if len(msg.LabelIds) > 0 {
179→		labelsJSON, _ := json.Marshal(msg.LabelIds)
180→		e.Labels = string(labelsJSON)
181→	}
182→
183→	return e
184→}
185→
186→func upsertContactsForMessage(d *sql.DB, source, direction string, e *RawMessage, incrementCount bool) error {
187→	timestamp := e.Date
188→	if direction == "inbound" {
189→		return upsertContact(d, source, e.FromEmail, timestamp, incrementCount)
190→	}
191→
192→	recipients := append(parseRecipients(e.ToEmails), parseRecipients(e.CcEmails)...)
193→	for _, recipient := range recipients {
194→		if err := upsertContact(d, source, recipient, timestamp, incrementCount); err != nil {
195→			return err
196→		}
197→	}
198→	return nil
199→}
200→
201→func upsertContact(d *sql.DB, source, emailAddress, activityAt string, incrementCount bool) error {
202→	emailAddress = strings.ToLower(strings.TrimSpace(emailAddress))
203→	if emailAddress == "" {
204→		return nil
205→	}
206→	domain := ""
207→	parts := strings.SplitN(emailAddress, "@", 2)
208→	if len(parts) == 2 {
209→		domain = parts[1]
210→	}
211→
212→	_, err := d.Exec(`
213→		INSERT INTO contacts (id, source, email, domain, last_activity_at, email_count, last_emailed_at)
214→		VALUES (?, ?, ?, ?, ?, 1, ?)
215→		ON CONFLICT(source, email) DO UPDATE SET
216→			domain = CASE WHEN excluded.domain != '' THEN excluded.domain ELSE contacts.domain END,
217→			last_activity_at = CASE
218→				WHEN contacts.last_activity_at = '' OR contacts.last_activity_at IS NULL OR excluded.last_activity_at > contacts.last_activity_at THEN excluded.last_activity_at
219→				ELSE contacts.last_activity_at
220→			END,
221→			last_emailed_at = CASE
222→				WHEN contacts.last_emailed_at = '' OR contacts.last_emailed_at IS NULL OR excluded.last_emailed_at > contacts.last_emailed_at THEN excluded.last_emailed_at
223→				ELSE contacts.last_emailed_at
224→			END,
225→			email_count = contacts.email_count + ?,
226→			updated_at = datetime('now')`,
227→		"contact:"+source+":"+emailAddress, source, emailAddress, domain, activityAt, activityAt, boolToInt(incrementCount),
228→	)
229→	return err
230→}
231→
232→func boolToInt(value bool) int {
233→	if value {
234→		return 1
235→	}
236→	return 0
237→}
238→
239→func extractEmail(header string) string {
240→	if i := strings.Index(header, "<"); i != -1 {
241→		if j := strings.Index(header, ">"); j != -1 {
242→			return header[i+1 : j]
243→		}
244→	}
245→	return strings.TrimSpace(header)
246→}
247→
248→func emailsToJSON(header string) string {
249→	if header == "" {
250→		return "[]"
251→	}
252→	parts := strings.Split(header, ",")
253→	emails := make([]string, 0, len(parts))
254→	for _, p := range parts {
255→		emails = append(emails, extractEmail(p))
256→	}
257→	data, _ := json.Marshal(emails)
258→	return string(data)
259→}
