400→func CanSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
401→	sendType = NormalizeSendType(sendType)
402→	if sendType == SendTypeManual {
403→		return nil
404→	}
405→	if now.IsZero() {
406→		now = time.Now()
407→	}
408→
409→	mailbox, usage, err := mailboxAndUsage(d, mailboxID, now)
410→	if err != nil {
411→		return err
412→	}
413→	if mailbox.Status != "active" {
414→		return fmt.Errorf("mailbox %s is %s", mailbox.Email, mailbox.Status)
415→	}
416→	if mailbox.ReputationScore > 0 && mailbox.ReputationScore < 40 {
417→		return fmt.Errorf("mailbox %s reputation is too low (%d)", mailbox.Email, mailbox.ReputationScore)
418→	}
419→	if !withinSendWindow(*mailbox, now) {
420→		return fmt.Errorf("mailbox %s is outside its send window (%s %02d:00-%02d:00)", mailbox.Email, mailbox.SendWindowTimezone, mailbox.SendWindowStartHour, mailbox.SendWindowEndHour)
421→	}
422→	if mailbox.LastBounceAt != "" && sendType == SendTypeFirstTouch {
423→		if bouncedAt, err := time.Parse(time.RFC3339, mailbox.LastBounceAt); err == nil && now.UTC().Before(bouncedAt.Add(24*time.Hour)) {
424→			return fmt.Errorf("mailbox %s is cooling off after a recent bounce until %s", mailbox.Email, bouncedAt.Add(24*time.Hour).Format(time.RFC3339))
425→		}
426→	}
427→
428→	firstTouchCap, followUpCap, replyCap := effectiveCaps(*mailbox)
429→
430→	switch sendType {
431→	case SendTypeFirstTouch:
432→		if firstTouchCap > 0 && usage.FirstTouchesSent >= firstTouchCap {
433→			return fmt.Errorf("mailbox %s has reached its first-touch daily cap (%d/%d)", mailbox.Email, usage.FirstTouchesSent, firstTouchCap)
434→		}
435→	case SendTypeFollowUp:
436→		if followUpCap > 0 && usage.FollowUpsSent >= followUpCap {
437→			return fmt.Errorf("mailbox %s has reached its follow-up daily cap (%d/%d)", mailbox.Email, usage.FollowUpsSent, followUpCap)
438→		}
439→	case SendTypeReply:
440→		if replyCap > 0 && usage.RepliesSent >= replyCap {
441→			return fmt.Errorf("mailbox %s has reached its reply daily cap (%d/%d)", mailbox.Email, usage.RepliesSent, replyCap)
442→		}
443→	}
444→
445→	if mailbox.MinGapMinutes > 0 {
446→		lastSentAt, err := latestMailboxOutboundAt(d, effectiveTransportEmail(*mailbox))
447→		if err != nil {
448→			return err
449→		}
450→		if !lastSentAt.IsZero() {
451→			nextAllowed := lastSentAt.Add(time.Duration(mailbox.MinGapMinutes) * time.Minute)
452→			if now.UTC().Before(nextAllowed) {
453→				return fmt.Errorf("mailbox %s is cooling down until %s", mailbox.Email, nextAllowed.Format(time.RFC3339))
454→			}
455→		}
456→	}
457→
458→	return nil
459→}
