461→func RecordSend(d *sql.DB, mailboxID, sendType string, now time.Time) error {
462→	sendType = NormalizeSendType(sendType)
463→	if sendType == SendTypeManual {
464→		return nil
465→	}
466→	if now.IsZero() {
467→		now = time.Now()
468→	}
469→
470→	_, err := d.Exec(`
471→		INSERT INTO mailbox_daily_usage (
472→			mailbox_id, usage_day, first_touches_sent, follow_ups_sent, replies_sent
473→		) VALUES (?, ?, 0, 0, 0)
474→		ON CONFLICT(mailbox_id, usage_day) DO NOTHING`,
475→		mailboxID, dayKey(now),
