503→	}
504→	if opts.SentAt.IsZero() {
505→		opts.SentAt = time.Now()
506→	}
507→	if existing, err := ActiveEnrollmentForContact(d, opts.MailboxID, opts.ContactEmail); err != nil {
508→		return nil, nil, err
509→	} else if existing != nil {
