169→func executeDispatch(srv *gm.Service, d *sql.DB, dispatch []sequence.DispatchTask) ([]dispatcherExecutionResult, error) {
170→	results := make([]dispatcherExecutionResult, 0, len(dispatch))
171→	for _, item := range dispatch {
172→		if !item.Ready {
173→			continue
174→		}
175→
176→		attemptedAt := timeNow()
177→		fromAddress := strings.TrimSpace(item.TransportEmail)
178→		if fromAddress == "" {
179→			fromAddress = strings.TrimSpace(item.SelectedMailboxEmail)
180→		}
181→		if fromAddress == "" {
182→			results = append(results, dispatcherExecutionResult{
183→				TaskID:       item.ID,
184→				ContactEmail: item.ContactEmail,
185→				MailboxEmail: item.SelectedMailboxEmail,
186→				Status:       "failed",
187→				Error:        "no transport address available for task",
188→			})
189→			continue
190→		}
191→
192→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
193→			To:       item.ContactEmail,
194→			Subject:  dispatchSubject(item),
195→			Body:     item.RenderedBody,
196→			ThreadID: item.ThreadID,
197→		})
198→		if err != nil {
199→			if markErr := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, err); markErr != nil {
200→				return results, markErr
201→			}
202→			results = append(results, dispatcherExecutionResult{
203→				TaskID:       item.ID,
204→				ContactEmail: item.ContactEmail,
205→				MailboxEmail: item.SelectedMailboxEmail,
206→				Status:       "failed",
207→				Error:        err.Error(),
208→			})
209→			continue
210→		}
211→
212→		if err := sequence.MarkTaskAttempt(d, item.ID, attemptedAt, nil); err != nil {
213→			return results, err
214→		}
215→		if err := sequence.RecordSend(d, item.SelectedMailboxID, item.SendType, attemptedAt); err != nil {
216→			return results, fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
217→		}
218→		if err := email.StoreEmail(d, &email.RawMessage{
219→			ID:        sent.MessageID,
220→			Source:    "gmail",
221→			Direction: "outbound",
222→			ThreadID:  sent.ThreadID,
223→			Subject:   dispatchSubject(item),
224→			FromEmail: fromAddress,
225→			ToEmails:  recipientsJSON(item.ContactEmail),
226→			Date:      attemptedAt.UTC().Format(time.RFC3339),
227→			Labels:    `["SENT"]`,
228→		}); err != nil {
229→			return results, fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
230→		}
231→		if _, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
232→			TaskID:    item.ID,
233→			ThreadID:  sent.ThreadID,
234→			MessageID: sent.MessageID,
235→			MailboxID: item.SelectedMailboxID,
236→			SentAt:    attemptedAt,
237→		}); err != nil {
238→			return results, fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, item.ID, err)
239→		}
240→
241→		results = append(results, dispatcherExecutionResult{
242→			TaskID:       item.ID,
243→			ContactEmail: item.ContactEmail,
244→			MailboxEmail: item.SelectedMailboxEmail,
245→			MessageID:    sent.MessageID,
246→			Status:       "sent",
247→		})
248→	}
249→	return results, nil
250→}
