271→	dispatcherRunCmd.Flags().BoolVar(&dispatcherSyncReplies, "sync-replies", true, "Sync active-thread replies before evaluating the queue")
272→	dispatcherRunCmd.Flags().BoolVar(&dispatcherExecute, "execute", false, "Render and send ready tasks automatically")
273→	dispatcherRunCmd.Flags().StringVar(&dispatcherTransportEmail, "transport-email", "", "Transport mailbox to use for execution/rotation (defaults to connected Gmail account)")
274→	dispatcherCmd.AddCommand(dispatcherRunCmd)
275→	rootCmd.AddCommand(dispatcherCmd)
276→}
